wire a, b, c, d;
wire mysig;
wire derived;
assign mysig = a & b & c & d;
assign derived = ~mysig & b;

(* blackbox *)
module bbox_buf(output wire x, input wire a);
    assign x = a;
endmodule

(* keep *) wire mysig;
wire derived;
assign mysig = a & b;
assign derived = ~mysig;

wire load_n;
wire derived;
always @(posedge clk)
    derived <= load_n ? (derived + {8{load_n}}) : 8'b0;
